     7→const TAG_PALETTES = [
     8→  'bg-blue-100 text-blue-700 border-blue-200',
     9→  'bg-violet-100 text-violet-700 border-violet-200',
    10→  'bg-emerald-100 text-emerald-700 border-emerald-200',
