    18→function tagColor(tag: string): string {
    19→  let hash = 0
    20→  for (let i = 0; i < tag.length; i++) {
    21→    hash = (hash * 31 + tag.charCodeAt(i)) & 0xffffffff
    22→  }
    23→  return TAG_PALETTES[Math.abs(hash) % TAG_PALETTES.length]
    24→}
