    26→function highlight(text: string, query: string): React.ReactNode {
    27→  if (!query.trim()) return text
    28→  const idx = text.toLowerCase().indexOf(query.toLowerCase())
    29→  if (idx === -1) return text
    30→  return (
    31→    <>
    32→      {text.slice(0, idx)}
    33→      <mark className="bg-amber-100 text-amber-800 rounded-sm">{text.slice(idx, idx + query.length)}</mark>
    34→      {text.slice(idx + query.length)}
    35→    </>
    36→  )
    37→}
    38→
    39→function excerpt(text: string, query: string, maxLen = 160): string {
    40→  const idx = text.toLowerCase().indexOf(query.toLowerCase())
    41→  if (idx === -1) return text.slice(0, maxLen) + (text.length > maxLen ? '…' : '')
    42→  const start = Math.max(0, idx - 40)
    43→  const end = Math.min(text.length, idx + query.length + 100)
    44→  return (start > 0 ? '…' : '') + text.slice(start, end) + (end < text.length ? '…' : '')
    45→}
