    47→function groupByBook(results: SearchResult[]): Map<string, { title: string; items: SearchResult[] }> {
    48→  const map = new Map<string, { title: string; items: SearchResult[] }>()
    49→  for (const r of results) {
    50→    if (!map.has(r.bookId)) {
    51→      map.set(r.bookId, { title: r.bookTitle, items: [] })
    52→    }
    53→    map.get(r.bookId)!.items.push(r)
    54→  }
    55→  return map
    56→}
